function parseMoney(value) {
  if (value === undefined || value === null || value === '') return 0;
  const parsed = Number(String(value).replace(/[$,]/g, ''));
  return Number.isFinite(parsed) ? Math.round((parsed + Number.EPSILON) * 100) / 100 : 0;
}

function linkedInvoiceIds(payment) {
  const ids = [];
  for (const line of payment.Line ?? []) {
    for (const txn of line.LinkedTxn ?? []) {
      if (String(txn.TxnType ?? '').toLowerCase() === 'invoice' && txn.TxnId) ids.push(String(txn.TxnId));
    }
  }
  const memo = `${payment.PrivateNote ?? ''} ${payment.PaymentRefNum ?? ''}`;
  const anchorIds = memo.match(/invoice-[A-Za-z0-9_-]+/g) ?? [];
  return [...new Set([...ids, ...anchorIds])];
}

const payments = $input.all().map((item) => item.json).filter((payment) => payment?.Id);
const normalizedPayments = payments.map((payment) => ({
  qbo_payment_id: String(payment.Id),
  txn_date: payment.TxnDate ?? null,
  total_amount: parseMoney(payment.TotalAmt),
  customer_name: payment.CustomerRef?.name ?? payment.CustomerRef?.value ?? '',
  memo: payment.PrivateNote ?? payment.PaymentRefNum ?? '',
  linked_invoice_ids: linkedInvoiceIds(payment),
  raw_payload: payment,
}));

return [{ json: { normalizedPayments, qboPaymentCount: normalizedPayments.length } }];

const invoices = $input.all().map((item) => item.json).filter((invoice) => invoice?.Id);
const normalizedQboInvoices = invoices.map((invoice) => ({
  qbo_invoice_id: String(invoice.Id),
  doc_number: invoice.DocNumber ? String(invoice.DocNumber) : null,
  txn_date: invoice.TxnDate ?? null,
  total_amount: Number(invoice.TotalAmt ?? 0),
  customer_name: invoice.CustomerRef?.name ?? invoice.CustomerRef?.value ?? '',
}));
return [{ json: { normalizedQboInvoices, qboInvoiceCount: normalizedQboInvoices.length } }];

function money(value) {
  const parsed = Number(value ?? 0);
  return Number.isFinite(parsed) ? Math.round((parsed + Number.EPSILON) * 100) / 100 : 0;
}

function normalizeClientName(value) {
  let text = String(value ?? '').toLowerCase().replace(/&/g, ' and ');
  text = text.replace(/\([^)]*\)/g, ' ');
  const tokens = text.replace(/[^a-z0-9]+/g, ' ').split(/\s+/).filter((token) => token && !['and', 'the'].includes(token));
  let joined = tokens.join('');
  const suffixes = ['limitedliabilitycompany', 'corporation', 'company', 'incorporated', 'llc', 'inc', 'corp', 'co', 'pa'];
  let changed = true;
  while (changed) {
    changed = false;
    for (const suffix of suffixes) {
      if (joined.endsWith(suffix) && joined.length > suffix.length) {
        joined = joined.slice(0, -suffix.length);
        changed = true;
        break;
      }
    }
  }
  return joined;
}

function parseDate(value) {
  if (!value) return null;
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

function dateWithin(paymentDateValue, invoice, windowDays = 14) {
  const paymentDate = parseDate(paymentDateValue);
  const invoiceDate = parseDate(invoice.issue_date ?? invoice.due_date);
  if (!paymentDate || !invoiceDate) return false;
  return Math.abs(paymentDate.getTime() - invoiceDate.getTime()) <= windowDays * 24 * 60 * 60 * 1000;
}

function customerMatches(payment, invoice) {
  const customer = normalizeClientName(payment.customer_name);
  const invoiceCustomer = normalizeClientName(invoice.anchor_client_business_name);
  return Boolean(customer && invoiceCustomer && (customer === invoiceCustomer || invoiceCustomer.includes(customer)));
}

function amountMatches(payment, invoice) {
  return Math.abs(money(payment.total_amount) - money(invoice.total_amount)) <= 0.01;
}

function findMatch(payment, invoicesById, invoicesByNumber, qboInvoicesById, invoices) {
  for (const invoiceId of payment.linked_invoice_ids ?? []) {
    const qboInvoice = qboInvoicesById[invoiceId];
    const invoiceByDocNumber = qboInvoice?.doc_number ? invoicesByNumber[qboInvoice.doc_number] : null;
    if (invoiceByDocNumber) {
      return { match_status: 'matched', match_reason: 'linked_qbo_invoice_doc_number', invoice: invoiceByDocNumber, candidate_count: 1 };
    }
    if (invoicesById[invoiceId]) {
      return { match_status: 'matched', match_reason: 'linked_invoice_id', invoice: invoicesById[invoiceId], candidate_count: 1 };
    }
  }
  const candidates = invoices.filter((invoice) => customerMatches(payment, invoice) && amountMatches(payment, invoice) && dateWithin(payment.txn_date, invoice, 14));
  if (candidates.length === 1) return { match_status: 'matched', match_reason: 'customer_amount_date_window', invoice: candidates[0], candidate_count: 1 };
  if (candidates.length > 1) return { match_status: 'ambiguous', match_reason: 'multiple_customer_amount_date_window', invoice: null, candidate_count: candidates.length };
  return { match_status: 'unmatched', match_reason: 'no_invoice_match', invoice: null, candidate_count: 0 };
}

function allocate(collectionKey, collectedAmount, events) {
  const remainingEvents = events
    .map((event) => ({ ...event, remaining_amount: money(Number(event.source_amount ?? 0) - Number(event.already_allocated_amount ?? 0)) }))
    .filter((event) => event.remaining_amount > 0);
  const totalRemaining = money(remainingEvents.reduce((sum, event) => sum + event.remaining_amount, 0));
  const targetTotal = money(Math.min(collectedAmount, totalRemaining));
  if (targetTotal <= 0 || totalRemaining <= 0) return [];

  const rows = [];
  let allocatedSoFar = 0;
  remainingEvents.forEach((event, index) => {
    const isFinal = index === remainingEvents.length - 1;
    const exact = targetTotal * (event.remaining_amount / totalRemaining);
    let rounded = money(exact);
    let roundingDelta = 0;
    if (isFinal) {
      const finalAllocation = money(targetTotal - allocatedSoFar);
      roundingDelta = money(finalAllocation - rounded);
      rounded = finalAllocation;
    } else {
      allocatedSoFar = money(allocatedSoFar + rounded);
    }
    if (rounded > 0) {
      rows.push({
        allocation_key: `alloc_${collectionKey}_${event.revenue_event_key}`,
        collection_key: collectionKey,
        revenue_event_key: event.revenue_event_key,
        allocated_amount: rounded,
        allocation_method: 'invoice_prorata_by_remaining_source_amount',
        rounding_delta: roundingDelta,
      });
    }
  });
  return rows;
}

const payments = $('Normalize QBO Payments').first().json.normalizedPayments ?? [];
const qboInvoices = $('Normalize QBO Invoices').first().json.normalizedQboInvoices ?? [];
const qboInvoicesById = Object.fromEntries(qboInvoices.map((invoice) => [invoice.qbo_invoice_id, invoice]));
const agreements = $('Fetch Anchor Agreements').all().map((item) => item.json);
const agreementByRelationship = Object.fromEntries(agreements.map((agreement) => [agreement.anchor_relationship_id, agreement]));
const invoices = $('Fetch Anchor Invoices').all().map((item) => ({
  ...item.json,
  anchor_client_business_name: agreementByRelationship[item.json.anchor_relationship_id]?.client_business_name ?? null,
}));
const invoicesById = Object.fromEntries(invoices.map((invoice) => [invoice.anchor_invoice_id, invoice]));
const invoicesByNumber = Object.fromEntries(invoices.filter((invoice) => invoice.invoice_number).map((invoice) => [String(invoice.invoice_number), invoice]));
const allocationsByEvent = $('Fetch Existing Allocations').all().reduce((acc, item) => {
  const row = item.json;
  acc[row.revenue_event_key] = money((acc[row.revenue_event_key] ?? 0) + Number(row.allocated_amount ?? 0));
  return acc;
}, {});
const eventsByInvoice = {};
for (const item of $('Fetch Revenue Events').all()) {
  const event = item.json;
  if (!event.anchor_invoice_id) continue;
  (eventsByInvoice[event.anchor_invoice_id] ??= []).push({
    ...event,
    already_allocated_amount: allocationsByEvent[event.revenue_event_key] ?? 0,
  });
}

const collectionRows = [];
const allocationRows = [];
const matchCounts = {};
for (const payment of payments) {
  const match = findMatch(payment, invoicesById, invoicesByNumber, qboInvoicesById, invoices);
  matchCounts[match.match_status] = (matchCounts[match.match_status] ?? 0) + 1;
  const invoice = match.invoice;
  const collectionKey = `qbo_payment_${payment.qbo_payment_id}`;
  collectionRows.push({
    collection_key: collectionKey,
    source_system: 'qbo',
    source_payment_id: payment.qbo_payment_id,
    anchor_invoice_id: invoice?.anchor_invoice_id ?? null,
    anchor_relationship_id: invoice?.anchor_relationship_id ?? null,
    qbo_payment_id: payment.qbo_payment_id,
    collected_at: payment.txn_date,
    collected_amount: money(payment.total_amount),
    currency: 'USD',
    collection_status: 'collected',
    raw_payload: {
      ...payment.raw_payload,
      profit_match_status: match.match_status,
      profit_match_reason: match.match_reason,
      profit_candidate_count: match.candidate_count,
    },
  });
  if (invoice?.anchor_invoice_id) {
    allocationRows.push(...allocate(collectionKey, money(payment.total_amount), eventsByInvoice[invoice.anchor_invoice_id] ?? []));
  }
}

return [{
  json: {
    collectionRows,
    allocationRows,
    summary: {
      qboPaymentCount: payments.length,
      qboInvoiceCount: qboInvoices.length,
      cashCollectionRowCount: collectionRows.length,
      allocationRowCount: allocationRows.length,
      matchCounts,
      allocationAmount: money(allocationRows.reduce((sum, row) => sum + row.allocated_amount, 0)),
      note: 'QBO is the cash source of truth. Unmatched or ambiguous payments are inserted without Anchor invoice allocation and surface in profit_unallocated_cash_collections.',
    },
  },
}];

const summary = $('Build Cash Collections And Allocations').first().json.summary;
const cashRows = $('Upsert Cash Collections').all().map((item) => item.json);
const allocationRows = $input.all().map((item) => item.json);
return [{
  json: {
    status: 'ok',
    ...summary,
    upsertedCashCollectionCount: cashRows.length,
    upsertedAllocationCount: allocationRows.length,
    sampleCashCollections: cashRows.slice(0, 10),
    sampleAllocations: allocationRows.slice(0, 10),
  },
}];

